PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?sales_manager a :Sales_Manager .
    ?sales_manager p:name ?name .
    ?sales_manager p:working_arrangement ?working_arrangement_f .
    FILTER(STR(?working_arrangement_f) = "Hybrid")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?marketing_specialist a :MarketingSpecialists .
    ?marketing_specialist p:name ?name .
    ?marketing_specialist p:working_arrangement ?working_arrangement_f .
    FILTER(STR(?working_arrangement_f) = "Hybrid")
    BIND(?name AS ?o0)
  }
}

